import { createClient } from "@/lib/supabase/server";
import AssignmentManager from "@/components/admin/AssignmentManager";

export const revalidate = 0;

export default async function AssignmentsPage() {
  const supabase = await createClient();

  const [
    { data: teachers },
    { data: students },
    { data: forms },
    { data: periods },
    { data: classes },
    { data: assignments },
  ] = await Promise.all([
    supabase.from("profiles").select("id, full_name, employee_id, subject").eq("role", "teacher").order("full_name"),
    supabase.from("profiles").select("id, full_name, student_number").eq("role", "student").order("full_name"),
    supabase.from("evaluation_forms").select("id, title").eq("is_active", true).order("created_at"),
    supabase.from("evaluation_periods").select("id, title, end_at").eq("is_active", true).order("created_at"),
    supabase.from("classes").select("id, name, academic_year").order("name"),
    supabase
      .from("teacher_assignments")
      .select(`
        id, created_at,
        student:profiles!teacher_assignments_student_id_fkey (id, full_name, student_number),
        teacher:profiles!teacher_assignments_teacher_id_fkey (id, full_name, employee_id, subject),
        form:evaluation_forms!teacher_assignments_form_id_fkey (id, title),
        period:evaluation_periods!teacher_assignments_period_id_fkey (id, title),
        class:classes (id, name)
      `)
      .order("created_at", { ascending: false }),
  ]);

  return (
    <div className="animate-fade-in">
      <div className="mb-6">
        <h1 className="text-2xl font-black text-primary">จับคู่ครู–นักเรียน</h1>
        <p className="text-base-black/50 text-sm mt-1">กำหนดนักเรียนคนไหนประเมินครูคนไหน</p>
      </div>

      <AssignmentManager
        teachers={teachers ?? []}
        students={students ?? []}
        forms={forms ?? []}
        periods={periods ?? []}
        classes={classes ?? []}
        initialAssignments={assignments ?? []}
      />
    </div>
  );
}
